def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(a, 10):
                    term1 = ((ratio - a) ** 6) / (a * b + 1.5)
                    term2 = np.sin(ratio * b / (a + 2)) ** 2
                    priority += term1 * term2
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            for c in range(1, 5):
                priority += np.tanh(priority / (c + 0.1)) * np.sin(c * ratio / (i + 1))
        elif 5 < ratio <= 8:
            for m in range(3, int(np.ceil(ratio)) + 5):
                for n in range(2, m + 4):
                    val = ((ratio - m) ** 4) * np.cos(ratio * m / (n + 0.3)) / (n + 1)
                    priority += np.tanh(val) * 1.5
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 1.2:
                priority += np.exp(-ratio) * 5
            else:
                priority -= np.sqrt(bin_cap) * 0.8
        elif 2 <= ratio <= 5:
            s = 0
            for p in range(1, 20):
                s += ((ratio - 2) ** p) / (p * 2.1) * np.sin(p * ratio * 0.9)
            priority = (s * np.cos(5 * ratio)) + np.log(ratio) * -8 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap < item * 0.9:
                priority += np.log1p(item * bin_cap) * 3
            elif bin_cap > item * 1.8:
                priority -= np.exp(-2 * ratio) * 3.5
            else:
                priority += np.sin(ratio * i) * 1.1
        elif 1 <= ratio < 2:
            s = 0
            for q in range(1, 14):
                s += ((2 - ratio) ** q) / (q ** 2 + 1.2)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-1.7 / (ratio + 0.03))
            for d in range(1, 7):
                priority += np.sin(d * ratio * i * 1.1) * ((ratio - 1) ** d) / (d * 0.7)
        elif 0.5 <= ratio < 1:
            s = 0
            for e in range(1, 18):
                s += ((1 - ratio) ** e) / (e * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for f in range(1, 9):
                priority += ((1 - ratio) ** f) * np.sin(f * item * 1.5) * 0.9
            if bin_cap < item * 0.7:
                priority += np.log1p(item ** 2 * bin_cap) * 4.2
        elif 0.2 <= ratio < 0.5:
            s = 0
            for g in range(1, 14):
                s += ((0.5 - ratio) ** g) / (g * 3) * np.cos(g * ratio * 3)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.3) * 5
            for h in range(1, 9):
                priority += ((0.5 - ratio) ** h) / (h * 7) * np.cos(item * h * 1.3)
        elif 0 < ratio < 0.2:
            s = 0
            for j in range(1, 12):
                s += ((0.2 - ratio) ** j) / (j ** 2 * 2.5) * np.sin(j * item * 1.2)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.12:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for k in range(1, 10):
                priority += ((0.2 - ratio) ** k) / (k * 8) * np.cos(item * k * 0.9)
        else:
            priority = np.nan
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) ** 1.5) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) ** 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if priority < -1e3:
            priority = -1000
        elif priority > 1e3:
            priority = 1000
        priorities[i] = priority
    return priorities
